import{c as r,Z as o,Q as i,j as l,g as t,n,o as s,m as d}from"./chunks/framework.qjzPVSkb.js";const b=JSON.parse('{"title":"MoE","description":"混合专家模型——多个专家子网络 + 门控路由，用较少计算量实现更大模型容量","frontmatter":{"title":"MoE","description":"混合专家模型——多个专家子网络 + 门控路由，用较少计算量实现更大模型容量","difficulty":"advanced"},"headers":[],"relativePath":"terms/moe.md","filePath":"terms/moe.md"}'),h={name:"terms/moe.md"};function p(m,e,f,c,u,x){const a=o("DifficultyBadge");return i(),l("div",null,[e[0]||(e[0]=t("h1",{id:"moe",tabindex:"-1"},[n("MoE "),t("a",{class:"header-anchor",href:"#moe","aria-label":'Permalink to "MoE"'},"​")],-1)),s(a,{level:"advanced"}),e[1]||(e[1]=d('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>MoE（Mixture of Experts，混合专家模型）是一种稀疏激活的模型架构，它由<strong>多个&quot;专家&quot;子网络 + 一个门控路由机制</strong>组成。每次前向传播时，路由器只激活其中少数几个专家，用较少的计算量实现了远大于自身的模型容量。DeepSeek-V3、Mixtral 8x7B 等明星模型均采用此架构。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象一个大型医院有 100 位专科医生（专家），但每个病人来就诊时，不是找 100 位医生会诊（那样太慢太贵），而是由分诊台护士（门控路由）根据症状分配到最相关的 2~3 位医生。不同的病人会被分配给不同的医生组合。MoE 就是这种&quot;按需激活&quot;的思路——模型虽然庞大，但每次推理只激活一小部分参数，实现了&quot;大模型的容量 + 小模型的速度&quot;。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>MoE 架构的核心组件：</p><ol><li><strong>专家网络（Experts）</strong>：多个独立的前馈神经网络子模块。每个专家都有自己的参数，可以专注于不同类型的输入模式。例如有的专家擅长处理代词，有的擅长处理专业术语</li><li><strong>门控网络（Gating / Router）</strong>：一个轻量级的分类器，输入一个 Token 的表示向量，输出每个专家的&quot;适合度&quot;分数。通过 Softmax 归一化后，选择 Top-K 个分数最高的专家来实际处理该 Token</li><li><strong>稀疏激活（Sparse Activation）</strong>：关键特性——每个 Token 只激活 Top-K 个专家（通常 K=1 或 2），其余专家不参与计算。这意味着模型的总参数量可以极大（如 Mixtral 8x7B 共 47B 参数），但每次推理的活跃参数量只有 13B 左右</li></ol><p><strong>负载均衡</strong> 是 MoE 的最大挑战——如果路由器总是选择某几个&quot;热门&quot;专家，会导致计算资源浪费和训练不稳定。通常通过额外的辅助损失函数（Auxiliary Loss）来鼓励路由器均匀分配负载。</p><p>MoE 的代表模型：</p><table tabindex="0"><thead><tr><th>模型</th><th>总参数量</th><th>活跃参数量</th><th>专家数</th></tr></thead><tbody><tr><td>Mixtral 8x7B</td><td>46.7B</td><td>12.9B</td><td>8</td></tr><tr><td>DeepSeek-V2</td><td>236B</td><td>21B</td><td>160</td></tr><tr><td>DeepSeek-V3</td><td>671B</td><td>37B</td><td>256</td></tr></tbody></table><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/transformer.html">Transformer</a> —— MoE 通常用在 Transformer 的前馈网络（FFN）层替代标准的 Dense 层</li><li><a href="/ai-knowledge/terms/parameters.html">参数</a> —— MoE 的总参数量可以极大，但推理时只计算活跃参数</li><li><a href="/ai-knowledge/terms/training-inference.html">训练 / 推理</a> —— MoE 在推理效率上的优势最为显著</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>MoE 综述：<a href="https://arxiv.org/abs/2209.01667" target="_blank" rel="noreferrer">A Review of Sparse Expert Models in Deep Learning</a></li><li>Mixtral 技术报告：<a href="https://arxiv.org/abs/2401.04088" target="_blank" rel="noreferrer">Mixtral of Experts</a></li><li>DeepSeek-V3 技术报告：<a href="https://arxiv.org/abs/2412.19437" target="_blank" rel="noreferrer">DeepSeek-V3 Technical Report</a></li><li>深入理解：先用单个 Dense 模型理解 Transformer FFN 层的作用，再看 MoE 如何把一层拆成多个专家。</li></ul>',14))])}const _=r(h,[["render",p]]);export{b as __pageData,_ as default};
